diff --git a/llvm/lib/Transforms/Vectorize/VPlan.cpp b/llvm/lib/Transforms/Vectorize/VPlan.cpp
index e804f81c36db..02f94514f7f0 100644
--- a/llvm/lib/Transforms/Vectorize/VPlan.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlan.cpp
@@ -225,6 +225,30 @@ Value *VPTransformState::get(VPValue *Def, const VPLane &Lane) {
   if (Def->isLiveIn())
     return Def->getLiveInIRValue();

+  // If Def is defined by a VPInstruction, try to evaluate it if possible.
+  if (VPRecipeBase *Recipe = Def->getDefiningRecipe()) {
+    if (auto *VPInst = dyn_cast<VPInstruction>(Recipe)) {
+      // Handle binary ops with constant operands.
+      if (VPInst->getOpcode() == Instruction::Add ||
+          VPInst->getOpcode() == Instruction::Sub ||
+          VPInst->getOpcode() == Instruction::Mul) {
+        VPValue *Op0 = VPInst->getOperand(0);
+        VPValue *Op1 = VPInst->getOperand(1);
+        // Check if both operands are constants.
+        if (Op0->isLiveIn() && Op1->isLiveIn()) {
+          Value *V0 = Op0->getLiveInIRValue();
+          Value *V1 = Op1->getLiveInIRValue();
+          if (auto *C0 = dyn_cast<ConstantInt>(V0))
+            if (auto *C1 = dyn_cast<ConstantInt>(V1)) {
+              Constant *Result = ConstantExpr::get(VPInst->getOpcode(), C0, C1);
+              set(Def, Result, VPLane::getFirstLane());
+              return Result;
+            }
+        }
+      }
+    }
+  }
+
   if (hasScalarValue(Def, Lane))
     return Data.VPV2Scalars[Def][Lane.mapToCacheIndex(VF)];

